window.iconPickerVue=new Vue({el:"#iconPickerVue",data:function(){return{targetInputField:"",targetIconTag:"",iconPickerModal:null}},mounted:function(){$(".icp-auto").iconpicker({title:!1,templates:{search:'<input type="search" class="form-control iconpicker-search" placeholder="" />'}}),$("#inline-picker").on("iconpickerSelected",i=>{var e=i.iconpickerInstance.options.fullClassFormatter(i.iconpickerValue);this.targetInputField&&$("#"+this.targetInputField).val(e),this.targetIconTag&&$("#"+this.targetIconTag).replaceWith('<i id="'+this.targetIconTag+'" class="'+e+'"></i>'),null!=this.iconPickerModal&&this.iconPickerModal.hide()})},methods:{show:function(i,e){this.targetInputField=i,this.targetIconTag=e,null==this.iconPickerModal&&(this.iconPickerModal=new bootstrap.Modal($("#iconPickerModal"),{keyboard:!1})),this.iconPickerModal.show()}}});
